WebLink.url:
var oppnum = "{!Contact.SYS_Number_of_Open_Opps__c}"; 

if( oppnum != "0") 
{alert ("Please create the request from the open opportunity."); 
} 
else 
{ 

var AccountID = "{!Contact.SYS_Account_ID__c}"; 
var UserName = "{!$User.FirstName}+ +{!$User.LastName}"; 
var UserEmail = "{!$User.Email}"; 
var UserID = "{!$User.Id}"; 
var UserRoleID = "{!$UserRole.Id}"; 
var ContactID = "{!Contact.Id}"; 


var url = "/flow/Request?VarAccountID="+AccountID+"&VarUserName="+UserName ; 
url= url + "&VarUserEmail="+UserEmail+"&VarUserID="+UserID ; 
url= url + "&VarContactID="+ContactID+"&VarUserRoleID="+UserRoleID ; 
url= url + "&retURL=/"+ContactID ; 


window.parent.location= url; 
}
